    // We should use a structure that allows us to track the *minimum time* to reach any cell, 
    // and if times are equal, the *maximum color* that can reach it at that minimum time.

    // Initialize distances (time) and colors for all cells
    // dist[r][c]: minimum time to reach (r, c)
    const dist = Array(n).fill(0).map(() => Array(m).fill(Infinity));
    // color_at_time[r][c]: the color assigned to (r, c) at the earliest time it was reached.
    const color_at_time = Array(n).fill(0).map(() => Array(m).fill(0));

    // Queue for BFS: [time, r, c, color]
    const queue = [];

    // Process initial sources
    for (const [r, c, color] of sources) {
        dist[r][c] = 0;
        color_at_time[r][c] = color;
        // Queue stores: [time, r, c]
        queue.push([0, r, c]);
        grid[r][c] = color;
    }

    const directions = [[0, 1], [0, -1], [1, 0], [-1, 0]];
    let head = 0;

    // BFS implementation
    while (head < queue.length) {
        const [time, r, c] = queue[head++];
        const currentColor = grid[r][c];
        const nextTime = time + 1;

        for (const [dr, dc] of directions) {
            const nr = r + dr;
            const nc = c + dc;

            if (nr >= 0 && nr < n && nc >= 0 && nc < m) {
                // Case 1: The neighbor is currently uncolored (or colored with a color that took longer to arrive)
                if (dist[nr][nc] === Infinity) {
                    // First time reaching (nr, nc)
                    dist[nr][nc] = nextTime;
                    color_at_time[nr][nc] = currentColor;
                    grid[nr][nc] = currentColor;
                    queue.push([nextTime, nr, nc]);
                } 
                // Case 2: The neighbor is already reached, check for better coloring
                else if (dist[nr][nc] === nextTime) {
                    // Reached at the exact same time step (nextTime).
                    // Apply the maximum color rule.
                    const existingColor = color_at_time[nr][nc];
                    if (currentColor > existingColor) {
                        // A higher color reaches this cell at the same time. Update it.
                        color_at_time[nr][nc] = currentColor;
                        grid[nr][nc] = currentColor;
                        // NOTE: We do NOT re-enqueue because the time is the same, 
                        // and this propagation only affects neighbors in subsequent time steps (time + 2, etc.).
                        // Since the color change only happens *at* this time step,
                        // the propagation from (nr, nc) in time + 1 onwards will use the new color.
                        // However, standard BFS/Dijkstra requires re-processing if the path weight/value changes.
                        // Since the BFS naturally proceeds layer by layer based on time, 
                        // we might need a more complex structure if a color change at time T influences propagation at time T+1.

                        // Let's re-examine the rule: "If multiple colors in the same time step arrive... adopt max color."
                        // The current BFS structure processes time sequentially. If grid[r][c] changes color from C1 to C2 at time T,
                        // its neighbors should receive C2 at time T+1, not C1.

                        // Since we only push to the queue when dist[nr][nc] == Infinity, if we update a cell already in the queue 
                        // or processed, we need to ensure its future propagations use the max color.

                        // Given the constraint complexity, the safest approach that mimics parallel expansion:
                        // 1. Keep track of the best [time, color] for every cell.
                        // 2. At each time step T, determine all cells that can be reached at time T.
                        // 3. For each cell, find the max color among all arrivals at time T.
                        // This requires a level-by-level BFS (iterative approach).
                    }
                    // If currentColor <= existingColor, no update is needed.
                }
                // Case 3: Reached earlier (dist[nr][nc] < nextTime). Ignore.
            }
        }
    }

    // --- Re-implementing using Level-by-Level BFS to handle simultaneous arrivals ---

    // Re-initialize state for Level-by-Level BFS
    const finalGrid = Array(n).fill(0).map(() => Array(m).fill(0));
    // dist[r][c] = minimum time
    const minTime = Array(n).fill(0).map(() => Array(m).fill(Infinity));

    // Queue stores: [r, c] for the current time step
    let currentQueue = [];

    for (const [r, c, color] of sources) {
        minTime[r][c] = 0;
        finalGrid[r][c] = color;
        currentQueue.push([r, c]);
    }

    let time = 0;
    while (currentQueue.length > 0) {
        const nextQueue = [];
        const neighborsToColor = new Map(); // Key: "r,c", Value: {color: max_color, arriving_time: time + 1}

        // Process all cells colored at time T
        for (const [r, c] of currentQueue) {
            const currentColor = finalGrid[r][c];
            const nextTime = time + 1;

            // Check neighbors
            for (const [dr, dc] of directions) {
                const nr = r + dr;
                const nc = c + dc;

                if (nr >= 0 && nr < n && nc >= 0 && nc < m) {
                    const key = `${nr},${nc}`;

                    // If the neighbor hasn't been reached yet, or if it can be reached at the same time
                    // as previously recorded, it is a candidate for simultaneous coloring at nextTime.
                    if (minTime[nr][nc] > nextTime) {
                        if (!neighborsToColor.has(key)) {
                            neighborsToColor.set(key, { color: 0, time: nextTime });
                        }
                        const entry = neighborsToColor.get(key);

                        if (nextTime < entry.time) {
                            // Should not happen if we process layer by layer correctly, but for robustness:
                            entry.time = nextTime;
                            entry.color = currentColor;
                        } else if (nextTime === entry.time) {
                            // Simultaneous arrival: take max color
                            entry.color = Math.max(entry.color, currentColor);
                        }
                    } else if (minTime[nr][nc] === nextTime) {
                        // Already marked to be colored at this time step, update color if max
                        const keyExisting = `${nr},${nc}`;
                        if (neighborsToColor.has(keyExisting)) {
                             const entry = neighborsToColor.get(keyExisting);
                             entry.color = Math.max(entry.color, currentColor);
                        } else {
                            // This cell was already marked by another source arriving at time T+1. Update it.
                            neighborsToColor.set(keyExisting, { color: Math.max(entry ? entry.color : 0, currentColor), time: nextTime });
                        }
                    }
                }
            }
        }

        // Apply updates determined for time + 1
        for (const [key, data] of neighborsToColor.entries()) {
            const [nr_str, nc_str] = key.split(',');
            const nr = parseInt(nr_str);
            const nc = parseInt(nc_str);

            // Only update if this time is the *new minimum time* for this cell
            if (data.time < minTime[nr][nc]) {
                minTime[nr][nc] = data.time;
                finalGrid[nr][nc] = data.color;
                nextQueue.push([nr, nc]);
            } else if (data.time === minTime[nr][nc]) {
                // If time is equal to the known minimum time, take the max color
                finalGrid[nr][nc] = Math.max(finalGrid[nr][nc], data.color);
            }
        }

        currentQueue = nextQueue;
        time++;
    }

    return finalGrid;
